// PlayoffMenu.js
import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { aplicarAscensosDescensos } from "../generation/PlayoffManager";
import { reorganizarGrupos } from "../generation/reorganizarGruposPorGeografia";

function PlayoffMenu() {
    const [playoffs, setPlayoffs] = useState({});
    const [rondaActual, setRondaActual] = useState(0);
    const navigate = useNavigate();

    useEffect(() => {
        const data = JSON.parse(localStorage.getItem("playoffs_actuales")) || {};
        setPlayoffs(data);
    }, []);

    useEffect(() => {
        // Detectar fin de playoffs
        if (playoffs.rondas && rondaActual >= playoffs.rondas.length) {
            const equipos = JSON.parse(localStorage.getItem("equipos")) || [];
            const clasificaciones = JSON.parse(localStorage.getItem("clasificacion")) || {};

            // Determinar ganadores de última ronda
            const ganadores = playoffs.rondas[rondaActual - 1].map(p => {
                const { golesLocal, golesVisitante, local, visitante } = p;
                return golesLocal > golesVisitante ? local.id : visitante.id;
            });

            const playoffsConGanadores = { ...playoffs, ganadores };
            const actualizados = aplicarAscensosDescensos(playoffsConGanadores, clasificaciones, equipos);
            const reorganizados = reorganizarGrupos(actualizados);

            localStorage.setItem("equipos", JSON.stringify(reorganizados));
            navigate("/league-generation");
        }
    }, [rondaActual, playoffs]);

    const jugarPartido = (local, visitante) => {
        const golesLocal = Math.floor(Math.random() * 5);
        const golesVisitante = Math.floor(Math.random() * 5);
        return { golesLocal, golesVisitante };
    };

    const jugarRonda = () => {
        const nuevaRonda = playoffs.rondas[rondaActual].map(({ local, visitante }) => {
            const resultado = jugarPartido(local, visitante);
            return { local, visitante, ...resultado, jugado: true };
        });

        const nuevasPlayoffs = { ...playoffs };
        nuevasPlayoffs.rondas[rondaActual] = nuevaRonda;

        localStorage.setItem("playoffs_actuales", JSON.stringify(nuevasPlayoffs));
        setPlayoffs(nuevasPlayoffs);
        setRondaActual(prev => prev + 1);
    };

    return (
        <div className="playoff-menu">
            <h1>Playoffs</h1>
            {playoffs.rondas && playoffs.rondas[rondaActual] ? (
                <>
                    <h2>Ronda {rondaActual + 1}</h2>
                    {playoffs.rondas[rondaActual].map((p, idx) => (
                        <div key={idx}>
                            {p.local.nombre} vs {p.visitante.nombre}
                            {p.jugado ? ` => ${p.golesLocal} - ${p.golesVisitante}` : ""}
                        </div>
                    ))}
                    <button onClick={jugarRonda}>Jugar Ronda</button>
                </>
            ) : (
                <p>Playoffs finalizados. Generando nueva temporada...</p>
            )}
        </div>
    );
}

export default PlayoffMenu;
